// ────────────────────────────────────────────────────────────────────────────
// pixel drawing 
// ────────────────────────────────────────────────────────────────────────────
void plot_pixel(int x, int y, short int color) {
    if (x<0||x>319||y<0||y>239) return;
    back_buffer[y][x] = color;
    //update_audio();
}

void draw_rect(int x, int y, int w, int h, short int color) {
    for (int r = 0; r < h; r++)
        for (int c = 0; c < w; c++)
            plot_pixel(x+c, y+r, color);
}

void draw_circle(int cx, int cy, int r, short int color) {
    int x = 0, y = r, d = 1 - r;
    while (x <= y) {
        update_audio();
        plot_pixel(cx+x,cy+y,color); plot_pixel(cx-x,cy+y,color);
        plot_pixel(cx+x,cy-y,color); plot_pixel(cx-x,cy-y,color);
        plot_pixel(cx+y,cy+x,color); plot_pixel(cx-y,cy+x,color);
        plot_pixel(cx+y,cy-x,color); plot_pixel(cx-y,cy-x,color);
        if (d < 0) d += 2*x+3;
        else { d += 2*(x-y)+5; y--; }
        x++;
    }
}

void fill_circle(int cx, int cy, int r, short int color) {
    for (int dy = -r; dy <= r; dy++)
        for (int dx = -r; dx <= r; dx++)
            if (dx*dx + dy*dy <= r*r)
                plot_pixel(cx+dx, cy+dy, color);
}

int abs(int x) { return x > 0 ? x : -x; }
void swap(int *x, int *y) { int t = *x; *x = *y; *y = t; }

void line(int x0, int y0, int x1, int y1, short color) {
    //update_audio();
    int steep = abs(y1-y0) > abs(x1-x0);
    if (steep)  { swap(&x0,&y0); swap(&x1,&y1); }
    if (x0>x1)  { swap(&x0,&x1); swap(&y0,&y1); }
    int dx = x1-x0, dy = abs(y1-y0);
    int err = -(dx/2), y = y0, ys = y0<y1 ? 1 : -1;
    for (int i = x0; i <= x1; i++) {
        if (steep) plot_pixel(y,i,color); else plot_pixel(i,y,color);
        err += dy;
        if (err > 0) { y += ys; err -= dx; }
    }
}

void clear(short color) {
	for(int y = 0; y < 240; y++){
        update_audio();
        for(int x = 0; x < 320; x++){
            plot_pixel(x,y,color);
        }
    }
}

// scanline-fill a convex quad
// uses two slightly different fill modes to handle quads above/below screen center
void quad(int x0, int y0, int x1, int y1,
          int x2, int y2, int x3, int y3, short color) {
    int xs[4] = {x0,x1,x2,x3};
    int ys[4] = {y0,y1,y2,y3};

    int ymin = ys[0], ymax = ys[0];
    for (int i = 1; i < 4; i++) {
        if (ys[i] < ymin) ymin = ys[i];
        if (ys[i] > ymax) ymax = ys[i];
    }

    if (((x0>160)&&(y0>120)) || ((x0<160)&&(y0<120))) {
        // fill interior (exclusive top edge)
        for (int y = ymin+1; y < ymax; y++) {
            int intersections[4]; int count = 0;
            for (int i = 0; i < 4; i++) {
                int ax=xs[i], ay=ys[i], bx=xs[(i+1)%4], by=ys[(i+1)%4];
                if ((y>ay&&y<=by)||(y>by&&y<=ay)) {
                    intersections[count++] = ax + (y-ay)*(bx-ax)/(by-ay);
                }
            }
            for (int a = 0; a < count-1; a++)
                for (int b = a+1; b < count; b++)
                    if (intersections[a]>intersections[b]) {
                        int tmp=intersections[a];
                        intersections[a]=intersections[b];
                        intersections[b]=tmp;
                    }
            for (int a = 0; a < count-1; a += 2)
                for (int x = intersections[a]+1; x < intersections[a+1]; x++)
                    plot_pixel(x, y, color);
        }
    } else {
        // fill interior (inclusive edges)
        for (int y = ymin; y <= ymax; y++) {
            int intersections[4]; int count = 0;
            for (int i = 0; i < 4; i++) {
                int ax=xs[i], ay=ys[i], bx=xs[(i+1)%4], by=ys[(i+1)%4];
                if ((y>ay&&y<=by)||(y>by&&y<=ay)) {
                    intersections[count++] = ax + (y-ay)*(bx-ax)/(by-ay);
                }
            }
            for (int a = 0; a < count-1; a++)
                for (int b = a+1; b < count; b++)
                    if (intersections[a]>intersections[b]) {
                        int tmp=intersections[a];
                        intersections[a]=intersections[b];
                        intersections[b]=tmp;
                    }
            for (int a = 0; a < count-1; a += 2)
                for (int x = intersections[a]; x <= intersections[a+1]; x++)
                    plot_pixel(x, y, color);
        }
    }
}

// ────────────────────────────────────────────────────────────────────────────
// Pixel Art
// ────────────────────────────────────────────────────────────────────────────

void plot_picture(int* matrix, int rows, int cols, int xOffset, int yOffset, int pixelSize, short* colors) {
	short curr_col; 
	int draw_x;
	int draw_y;
	for(int x = 0; x < cols; x++){
        for(int y = 0; y < rows; y++){
			curr_col = colors[matrix[y * cols + x]];      
            update_audio();      
			for(int dy = 0; dy < pixelSize; dy++){
                for(int sx = 0; sx < pixelSize; sx++){
					
					draw_x = x * pixelSize + sx + xOffset;
					draw_y = y * pixelSize + dy + yOffset;
                    plot_pixel(draw_x, draw_y, curr_col);
                }
            }
        }
    }
}

