void plot_level_disp(int game_mode) {
	short colors[] = {BLACK, WHITE, BLUE, BLUE, BLUE, RED, BLUE};
    if (game_mode == -1) {
        colors[2]=GREEN;
        colors[3]=BLACK;
        colors[4]=BLACK;
        colors[6]=BLACK;
    } else if (game_mode == 0) {
        colors[2]=YELLOW;
        colors[3]=YELLOW;
        colors[4]=BLACK;
        colors[6]=BLACK;
    } else if (game_mode == 1) {
        colors[2]= ORANGE;
        colors[3]= ORANGE;
        colors[4]= ORANGE;
        colors[6]= BLACK;
    } else if (game_mode == 2) {
        colors[2]= RED;
        colors[3]= RED;
        colors[4]= RED;
        colors[6]= RED;
    } 
    colors[5] = colors[2];
	plot_picture(level_display, 25, 30, LEVEL_DISP_X, LEVEL_DISP_Y, LEVEL_DISP_PX_SIZE, colors);
}

