// Different game mode algorithms:
// 1. Random action: EASY LEVEL KEY0
int random_action(int m, int ac, int ar) {
    int actions[4] = {0,1,2,3};

    for (int i = 0; i < 4; i++) {
        int j = rand() % 4;
        int tmp = actions[i];
        actions[i] = actions[j];
        actions[j] = tmp;
    }

    for (int i = 0; i < 4; i++) {
        int a = actions[i];
        int nac = ac, nar = ar;

        if (a == 0) nar--;
        else if (a == 1) nar++;
        else if (a == 2) nac--;
        else if (a == 3) nac++;

        if (nac >= 0 && nac < COLS && nar >= 0 && nar < ROWS &&
            maps[m][nar][nac] == 0)
            return a;
    }

    return 0;
}


// 2. DFS: MEDIUM LEVEL KEY1:
int dfs_compute(int m, int sc, int sr, int tc, int tr, int *out) {
    int stack_c[MAX_PATH], stack_r[MAX_PATH];
    int stack_dir[MAX_PATH];

    int visited[ROWS][COLS] = {0};

    int top = 0;
    stack_c[0] = sc;
    stack_r[0] = sr;
    stack_dir[0] = 0;

    visited[sr][sc] = 1;

    while (top >= 0) {
        update_audio();
        int c = stack_c[top];
        int r = stack_r[top];

        if (c == tc && r == tr) {
            for (int i = 1; i <= top; i++)
                out[i-1] = stack_dir[i];
            return top;
        }

        int found = 0;

        for (int a = 0; a < 4; a++) {
            update_audio();
            int nc = c, nr = r;

            if (a==0) nr--;
            else if (a==1) nr++;
            else if (a==2) nc--;
            else if (a==3) nc++;

            if (nc>=0 && nc<COLS && nr>=0 && nr<ROWS &&
                !visited[nr][nc] && maps[m][nr][nc]==0) {

                top++;
                stack_c[top] = nc;
                stack_r[top] = nr;
                stack_dir[top] = a;

                visited[nr][nc] = 1;
                found = 1;
                break;
            }
        }

        if (!found) top--;
    }

    return 0;
}

void compute_dfs_path(int m, int ac, int ar) {
    dfs_len = dfs_compute(m, ac, ar, target_col, target_row, dfs_path);
    dfs_index = 0;
}

int dfs_next_action(int m, int ac, int ar) {
    if (dfs_index < dfs_len)
        return dfs_path[dfs_index++];
    return 0;
}

// Game mode switching
void set_mode(int new_mode, int *cm, int *px, int *py) {
    game_mode = new_mode;

    dfs_len = 0;
    dfs_index = 0;

    reset_round(cm, px, py);
}

// ────────────────────────────────────────────────────────────────────────────
// collision / detection
// ────────────────────────────────────────────────────────────────────────────

#define DAMP_VALUE 2

// check all 4 corners of the 8x8 ball bounding box for wall overlap
int hits_wall(int m, int px, int py) {
	
	//get the current tile the ball is in
	int col = px_to_col(px);
	int row = py_to_row(py);	
	
	//project ball to 3d
	int pz = get_z_from_xy(px,py, prev_tilt);
    int cx = projectPoint(px, py, pz).x;
    int cy = projectPoint(px, py, pz).y;

    //This helps prevent the ball from getting stuck when tilt changes
    int rdamp = DAMP_VALUE;
    int udamp = DAMP_VALUE;
    int ddamp = DAMP_VALUE;
    int ldamp = DAMP_VALUE;
    if (prev_tilt == 'r'){rdamp = 0; ldamp++;}
    else if (prev_tilt == 'l') {ldamp = 0; rdamp++;}
    else if (prev_tilt == 'u') {udamp = 0; ddamp++;}
    else if (prev_tilt == 'd') {ddamp = 0; udamp++;}
	
	//obtain 3d bounds
	int r = BALL_SIZE/2+1;
	int minBallX = cx-(r-ldamp);
	int minBallY = cy-(r-udamp);
	int maxBallX = cx+(r-rdamp);
	int maxBallY = cy+(r-ddamp);
	
	//for each of the 9 surrounding tiles:
	for (int i = -1; i <=1; i++){
		for (int j = -1; j<=1; j++){
            update_audio();
			
			//check if its an obstacle 
			if(maps[m][row+i][col+j]){
				
				//project to 3d
				int x = col_to_px(col+j);
				int y = row_to_py(row+i);
				int z = get_z_from_xy(x, y, prev_tilt);
				struct BoxPoints b = getBoxPoints(x,y,z);
				
				//obtain its bounding box
				int minX = b.ftl.x;
				int maxX = b.ftl.x;
				int minY = b.ftl.y;
				int maxY = b.ftl.y;
				
				struct TwoDPoint pts[8] = {b.ftl, b.ftr, b.fbl, b.fbr, b.btl, b.btr, b.bbl, b.bbr};

				for (int k = 1; k < 8; k++) {
                    update_audio();
    				if (pts[k].x < minX) minX = pts[k].x;
    				if (pts[k].x > maxX) maxX = pts[k].x;
    				if (pts[k].y < minY) minY = pts[k].y;
    				if (pts[k].y > maxY) maxY = pts[k].y;
				}

				if (prev_tilt == 'r' && j < 0) continue;
				if (prev_tilt == 'l' && j > 0) continue;
				if (prev_tilt == 'd' && i < 0) continue;
				if (prev_tilt == 'u' && i > 0) continue;
				
				//check for overlap	
				if (maxBallX >= minX && minBallX <= maxX &&
    				maxBallY >= minY && minBallY <= maxY) {return 1;}
				
				
							
			}
		}
	}
	
	return 0;
	
}

// check if ball center tile matches the target tile
int reached_target(int px, int py, int target_col, int target_row) {
	
    //ball 3d bounds
	int pz = get_z_from_xy(px,py, prev_tilt);
    int cx = projectPoint(px, py, pz).x;
    int cy = projectPoint(px, py, pz).y;

	int r = BALL_SIZE/2;
	int minBallX = cx-r;
	int minBallY = cy-r;
	int maxBallX = cx+r;
	int maxBallY = cy+r;
	
	//target 3d bounds
	int tx = col_to_px(target_col);
	int ty = row_to_py(target_row);
	int tz = get_z_from_xy(tx,ty,prev_tilt);
	
	int tcx = projectPoint(tx, ty, tz).x;
    int tcy = projectPoint(tx, ty, tz).y;
	
	int minTX = tcx-r;
	int minTY = tcy-r;
	int maxTX = tcx+r;
	int maxTY = tcy+r;
	
	//check overlap
	if (maxBallX >= minTX && minBallX <= maxTX &&
    				maxBallY >= minTY && minBallY <= maxTY) {return 1;}
	return 0;
}

// ────────────────────────────────────────────────────────────────────────────
// hardware I/O
// ────────────────────────────────────────────────────────────────────────────
void wait_for_vsync(void) {
    volatile int *ctrl = (int *)0xFF203020;
    *ctrl = 1;
    while ((*(ctrl+3) & 0x01) != 0){
        update_audio();
    }
}

volatile int *ps2 = (volatile int *)0xFF200100;
int ps2_read() {
    int val = *ps2;
    if (val & 0x8000) return val & 0xFF;
    return -1;
}

//  game over screen 
void go_delay(int amount) {
    volatile int d = 0;
    while (d < amount) {
        update_audio();
        d++;
    }
}

void draw_ring(int radius, short color) {
    int cx = 160, cy = 120;
    for (int y = 0; y < 240; y++)
        for (int x = 0; x < 320; x++) {
            update_audio();
            int dx = x - cx, dy = y - cy;
            if (dx*dx + dy*dy <= radius*radius)
                plot_pixel(x, y, color);
        }
}

void draw_ring_band(int inner, int outer, short color) {
    int cx = 160, cy = 120;
    for (int y = 0; y < 240; y++){
        update_audio();
        for (int x = 0; x < 320; x++) {
            int dx = x - cx, dy = y - cy;
            int d2 = dx*dx + dy*dy;
            if (d2 <= outer*outer && d2 >= inner*inner)
                plot_pixel(x, y, color);
        }
    }
}

void draw_go_letter(int letter, int tx, int ty, short color) {
    if (letter == 0) {   // G
        draw_rect(tx+2, ty,    10, 2, color);
        draw_rect(tx,   ty+2,   2, 8, color);
        draw_rect(tx+2, ty+10, 10, 2, color);
        draw_rect(tx+8, ty+6,   4, 2, color);
        draw_rect(tx+10,ty+6,   2, 6, color);
    }
    else if (letter == 1) {   // A
        draw_rect(tx+4, ty,     4, 2, color);
        draw_rect(tx,   ty+2,   2, 10, color);
        draw_rect(tx+10,ty+2,   2, 10, color);
        draw_rect(tx,   ty+6,  12, 2, color);
    }
    else if (letter == 2) {   // M
        draw_rect(tx,   ty,     2, 12, color);
        draw_rect(tx+10,ty,     2, 12, color);
        draw_rect(tx+2, ty,     2,  4, color);
        draw_rect(tx+8, ty,     2,  4, color);
        draw_rect(tx+4, ty+2,   4,  2, color);
    }
    else if (letter == 3) {   // E
        draw_rect(tx,   ty,     2, 12, color);
        draw_rect(tx+2, ty,     8,  2, color);
        draw_rect(tx+2, ty+5,   6,  2, color);
        draw_rect(tx+2, ty+10,  8,  2, color);
    }
    else if (letter == 4) {   // O
        draw_rect(tx+2, ty,    8,  2, color);
        draw_rect(tx,   ty+2,  2,  8, color);
        draw_rect(tx+10,ty+2,  2,  8, color);
        draw_rect(tx+2, ty+10, 8,  2, color);
    }
    else if (letter == 5) {   // V
        draw_rect(tx,   ty,    2,  8, color);
        draw_rect(tx+10,ty,    2,  8, color);
        draw_rect(tx+2, ty+8,  2,  2, color);
        draw_rect(tx+8, ty+8,  2,  2, color);
        draw_rect(tx+4, ty+10, 4,  2, color);
    }
    else if (letter == 6) {   // E
        draw_rect(tx,   ty,     2, 12, color);
        draw_rect(tx+2, ty,     8,  2, color);
        draw_rect(tx+2, ty+5,   6,  2, color);
        draw_rect(tx+2, ty+10,  8,  2, color);
    }
    else if (letter == 7) {   // R
        draw_rect(tx,   ty,    2, 12, color);
        draw_rect(tx+2, ty,    8,  2, color);
        draw_rect(tx+10,ty+2,  2,  4, color);
        draw_rect(tx+2, ty+5,  8,  2, color);
        draw_rect(tx+4, ty+7,  2,  2, color);
        draw_rect(tx+6, ty+9,  4,  3, color);
    }
}

void show_game_over_screen(void) {

    volatile int *pixel_ctrl = (int *)0xFF203020;
    *(pixel_ctrl+1) = (int)&Buffer2;
    *pixel_ctrl = 1;
    while ((*(pixel_ctrl+3) & 0x01) != 0);
    *(pixel_ctrl+1) = (int)&Buffer1;

    // phase 1: expanding rings from center
    short ring_colors[6] = {0x07FF, 0xF81F, 0xFFE0, 0xFD20, 0xF800, 0xFFFF};
    int max_radius = 210;

    for (int r = 0; r <= max_radius; r += 5) {
        int band = (r * 6) / max_radius;
        if (band >= 6) band = 5;
        draw_ring(r, ring_colors[band]);

        *(pixel_ctrl + 1) = (int)back_buffer;
        *pixel_ctrl = 1;
        wait_for_vsync();
        back_buffer = (back_buffer == Buffer1) ? Buffer2 : Buffer1;
        update_audio();

    }

    // fill fully black
    {int k = 0;
        while (k<10) {
            clear(BLACK);
            *(pixel_ctrl + 1) = (int)back_buffer;
            *pixel_ctrl = 1;
            back_buffer = (back_buffer == Buffer1) ? Buffer2 : Buffer1;
            wait_for_vsync();
            update_audio();
            k++;
        }
    
    }

    // wait for keypress
    int blink = 0;

    volatile int *ps2_ptr = (volatile int *)0xFF200100;
    while (*ps2_ptr & 0x8000) { 
        volatile int dummy = *ps2_ptr; 
        (void)dummy; 
    }
    while (!(*ps2_ptr & 0x8000)){
        plot_game_over();

        if (blink) {
            for(int y = 150; y < 200; y++){
                for(int x = 130; x < 180; x++){
                    plot_pixel(x,y,BLACK);
                }
            }
        }

        if(timer_hw_tick()){
            if(blink==0) blink++;
            else if(blink == 1)blink--;
        }



        *(pixel_ctrl + 1) = (int)back_buffer;
        *pixel_ctrl = 1;
        wait_for_vsync();
        back_buffer = (back_buffer == Buffer1) ? Buffer2 : Buffer1;

    }
    gameState = 0;

    
}




// clear screen and redraw all wall tiles for map m
void draw_map(int m, char tilt) {
	
    clear(BLACK);
	plot_logo();
	plot_scoreboard();
	plot_score(playerScore, computerScore);
	draw_timer(round_timer_sec);
    plot_level_disp(game_mode);
    plot_pause_button();


    for (int row = 0; row < ROWS; row++)
        for (int col = 0; col < COLS; col++)
            if (maps[m][row][col] == 1){
                update_audio();
                draw_wall_tile(col, row, tilt);
            }

    if (portal.active) draw_portals();

}


// ────────────────────────────────────────────────────────────────────────────
// round reset — pick new map, place both balls, spawn target
// ────────────────────────────────────────────────────────────────────────────
int justBounced = 0;
int cyclesSinceBounce;

void reset_round(int *cm, int *px, int *py) {
    round_timer_sec  = ROUND_TIME_SEC; 
    timer_tick_count = 0; 

    erase_portals();
    portal.active = 0;

    *cm = rand() % NUM_MAPS;
    draw_map(*cm, 'n');
    *px = col_to_px(1);
    *py = row_to_py(1);
    agent_px = col_to_px(2);
    agent_py = row_to_py(1);
    
    //draw_ball(*px, *py, COL_PLAYER, prev_tilt);
    if (game_mode != MODE_FREE)
        draw_ball(agent_px, agent_py, COL_AGENT, prev_tilt);

    dfs_len = 0;
    dfs_index = 0;
    spawn_target(*cm, 1, 1);
	prev_tilt = 'u';

    justBounced = 0;
    cyclesSinceBounce = 0;

}

// ────────────────────────────────────────────────────────────────────────────
// main game loop
// ────────────────────────────────────────────────────────────────────────────

int main(void) {
    volatile int *pixel_ctrl = (int *)0xFF203020;

    *(pixel_ctrl+1) = (int)&Buffer2;
    *pixel_ctrl = 1;
    while ((*(pixel_ctrl+3) & 0x01) != 0);
    *(pixel_ctrl+1) = (int)&Buffer1;

    int cm = 0; // Current map, start at first then be random

    // player starts at tile (1,1)
    int px = col_to_px(1);
    int py = row_to_py(1);
	
    // RL agent starts at tile (2,1), one tile right of player
    agent_px = col_to_px(2);
    agent_py = row_to_py(1);
    spawn_target(cm, 1, 1);
	

    int e0 = 0, skip = 0; //for ps2 keyboard
    int agent_tick = 0; //how fast to update RL model (speed)
    int phys_tick  = 0;

	int ballSpeed = 0;
    prev_tilt = 'n';

    timer_hw_init();

    // MPU6050 init
    GPIO_t *gpio = GPIO_BASE;
    gpio->DDR  &= ~((1 << SCL_PIN) | (1 << SDA_PIN));
    gpio->DATA &= ~((1 << SCL_PIN) | (1 << SDA_PIN));
    mpu_write_reg(gpio, REG_PWR_MGMT, 0x00);  // wake up
    mpu_write_reg(gpio, 0x1A, 0x03);           // low-pass filter

    while (1) {
        update_audio();

        if (gameState==0){ //Main Menu
            clear(BLACK);
            plot_main_menu();
            updateDodecahedron();
            theta = (theta + 1) % 360;
            plot_logo();
        }
        else if (gameState==1) { //GAME
            //drawings
            draw_map(cm, prev_tilt);
            draw_target(target_col, target_row, COL_TARGET);
            draw_ball(px, py, COL_PLAYER, prev_tilt);
            if (game_mode != MODE_FREE)
                draw_ball(agent_px, agent_py, COL_AGENT, prev_tilt);

            //calculations
            //Things that happen once per second
            if (timer_hw_tick()) {
                //Tickdown the timer
                round_timer_sec--;
                if (round_timer_sec <= 0) {
                    trigger_clip(snd_game_over, snd_game_over_len);
                    
                    volatile int d = 0; while (d < 2000000) d++;
                    show_game_over_screen();

                    playerScore = 0;
                    computerScore = 0;
                    round_timer_sec = ROUND_TIME_SEC;
                    ballSpeed   = 0;
                    prev_tilt  = 'n';
                    agent_tick = 0;
                    reset_round(&cm, &px, &py);
                    continue;
                }

                //move agent if a mode is active
                if (game_mode != MODE_FREE) {

                    int ac = px_to_col(agent_px);
                    int ar = py_to_row(agent_py);

                    agent_px = col_to_px(ac);
                    agent_py = row_to_py(ar);

                    int action = 0;

                    // MODE SWITCH
                    if (game_mode == MODE_RANDOM) { //key 0
                        action = random_action(cm, ac, ar);
                    }
                    else if (game_mode == MODE_DFS) { //key 1
                        if (dfs_index >= dfs_len) {
                            compute_dfs_path(cm, ac, ar); // recompute if needed
                        }
                        action = dfs_next_action(cm, ac, ar);
                    }
                    else if (game_mode == MODE_RL) { //key 2
                        action = qt_best_action(ac, ar, target_col, target_row, cm); //use the table c array thing
                    }

                    int nac = ac, nar = ar; //update positions

                    if (action == 0) nar--;
                    else if (action == 1) nar++;
                    else if (action == 2) nac--;
                    else if (action == 3) nac++;

                    if (nac >= 0 && nac < COLS && nar >= 0 && nar < ROWS && maps[cm][nar][nac] == 0) {
                        agent_px = col_to_px(nac);
                        agent_py = row_to_py(nar);
                    }
                }

            }

            int nx = px, ny = py;

            if(ballSpeed<15)
                ballSpeed++;
                
            if(prev_tilt == 'u'){
                ny-=ballSpeed;
            } 
            else if(prev_tilt == 'd') {
                ny+=ballSpeed;
            } 
            else if(prev_tilt == 'r'){
                nx+=ballSpeed;
            } 
            else if(prev_tilt == 'l'){
                nx-=ballSpeed;
            }
                    
            
            
            if (!hits_wall(cm, nx, ny)) {   
                px = nx; 
                py = ny;
            } 
            
            else {
                //trigger_sound(SOUND_WALL);
                if (!justBounced){
                    ballSpeed *= -1;
                    justBounced=1;
                }
            }

            // Portal spawn/despawn timer 
            portal_spawn_timer++;
            if (!portal.active && portal_spawn_timer >= PORTAL_SPAWN_INTERVAL) {
                portal_spawn_timer = 0;
                spawn_portal(cm, px, py);
            }
            if (portal.active) {
                portal.life--;
                if (portal.life <= 0) {
                    erase_portals();
                    portal.active = 0;
                    portal_spawn_timer = 0;
                }
            }

            // Portal teleport check (after moving ball) ────────────────────
            int dest_col, dest_row;
            if (check_portal(px, py, &dest_col, &dest_row)) {
        
                portal.active = 0;
                portal_spawn_timer = 0;
                // land the ball in the center of the destination tile
                px = col_to_px(dest_col);
                py = row_to_py(dest_row);
                ballSpeed = 0;   // brief pause after warp feels good

            }

            if (reached_target(px, py, target_col, target_row)) {
                playerScore++;
                trigger_clip(snd_target, snd_target_len);

                reset_round(&cm, &px, &py);
                agent_tick = 0;
                ballSpeed=0;
                prev_tilt = 'n';
                dfs_index = dfs_len = 0;

            }

            if (reached_target(agent_px, agent_py, target_col, target_row)) {
                computerScore++;
                trigger_clip(snd_target, snd_target_len);  

                reset_round(&cm, &px, &py);
                ballSpeed=0;
                prev_tilt = 'n';
                dfs_index = dfs_len = 0; // reset DFS state
                continue;
            }
                
            // ── PLAYER PHYSICS ────────────────────────────────────────────────
            update_audio();
            phys_tick++;
            if(justBounced){
                cyclesSinceBounce++;
            }
            if(cyclesSinceBounce == 2){
                justBounced = 0;
                cyclesSinceBounce = 0;
            }
            if (phys_tick >= 20) {
                phys_tick = 0;

                // advance portal animation
                if (portal.active) {
                    portal_frame_timer++;
                    if (portal_frame_timer >= PORTAL_ANIM_SPEED) {
                        portal_frame_timer = 0;
                        // erase old frame before drawing new one
                        erase_portals();
                        portal_frame = (portal_frame + 1) % PORTAL_FRAME_COUNT;
                        draw_portals();
                    }
                }
            }
            
            // ── ACCELEROMETER INPUT ───────────────────────────────────────────
            if (1) {
                unsigned char abuf[6];
                mpu_read_regs(gpio, REG_ACCEL_X_H, abuf, 6);
                short ax = -(short)((abuf[0] << 8) | abuf[1]);
                short ay = -(short)((abuf[2] << 8) | abuf[3]);

                int abs_ax = ax < 0 ? -ax : ax;
                int abs_ay = ay < 0 ? -ay : ay;

                int nx = px, ny = py;
                char new_tilt = 'n';

                if (abs_ax > TILT_THRESHOLD || abs_ay > TILT_THRESHOLD) {
                    if (abs_ax >= abs_ay) {
                        // X axis dominant
                        if (ax > 0) { new_tilt = 'l'; }
                        else        { new_tilt = 'r'; }
                    } else {
                        // Y axis dominant
                        if (ay > 0) { new_tilt = 'd'; }
                        else        { new_tilt = 'u'; }
                    }

                    if (new_tilt != prev_tilt) {
                        prev_tilt = new_tilt;
                        ballSpeed = 0;
                    }

                    // Move ball one tile if not hitting a wall
                    if (!hits_wall(cm, nx, ny)) {
                        px = nx;
                        py = ny;
                    }
                }
            }
            // ── END ACCELEROMETER INPUT ───────────────────────────────────────

        }
        else if (gameState==2) {
            plot_pause();
        }
        else if (gameState==3) {
            clear(BLACK);
            plot_logo();
            plot_movement();
            plot_diff();
            plot_back();
        }
        

		
        // PLAYER KEYBOARD INPUT 
        // PS2 protocol: 0xF0 = key release prefix, 0xE0 = extended key prefix
        int b;

        while ((b = ps2_read()) >= 0) {
            update_audio();
            if (skip) { skip=0; e0=0; continue; }   // discard key-release scan code
            if (b == 0xF0) { skip=1; continue; }    // next byte is a key release
            if (b == 0xE0) { e0=1;   continue; }    // next byte is extended key			
			
            if(b==0x29) { //space
                if(gameState==0) {
                    reset_round(&cm, &px, &py);
                    computerScore = 0;
                    playerScore = 0;
                    gameState = 1;
                }else if (gameState == 2){
                    gameState = 0;
                }else if (gameState == 3) {
                    gameState = 0;
                }else if (gameState ==4) {
                    gameState = 0;
                }
            }

            if (b==0x4D) {//P
                if(gameState == 1) {
                    gameState = 2;
                } else if (gameState ==2) {
                    gameState = 1;
                }
            }

			// MODE SWITCH KEYS (check first before player movement)
            if (!e0) {
                if (b == 0x45) {  // '0' — free/player only
                    if (gameState==1){
                        game_mode = MODE_FREE;
                        dfs_index = dfs_len = 0;
                        draw_map(cm, prev_tilt);
                        draw_target(target_col, target_row, COL_TARGET);
                        draw_ball(px, py, COL_PLAYER, prev_tilt);
                    }
                }
                else if (b == 0x16) {  // '1' — random
                    if (gameState==1){
                        game_mode = MODE_RANDOM;
                        dfs_index = dfs_len = 0;
                        draw_map(cm, prev_tilt);
                        draw_target(target_col, target_row, COL_TARGET);
                        if (game_mode != MODE_FREE)
                            draw_ball(agent_px, agent_py, COL_AGENT, prev_tilt);
                        draw_ball(px, py, COL_PLAYER, prev_tilt);
                    }
                    if(gameState ==0) {gameState =3;}
                }
                else if (b == 0x1E) {  // '2' — DFS
                    if (gameState==1){
                        game_mode = MODE_DFS;
                        dfs_index = dfs_len = 0;
                        draw_map(cm, prev_tilt);
                        draw_target(target_col, target_row, COL_TARGET);
                        if (game_mode != MODE_FREE)
                            draw_ball(agent_px, agent_py, COL_AGENT, prev_tilt);
                        draw_ball(px, py, COL_PLAYER, prev_tilt);
                    }
                }
                else if (b == 0x26) {  // '3' — RL
                    if (gameState==1){
                        game_mode = MODE_RL;
                        dfs_index = dfs_len = 0;
                        draw_map(cm, prev_tilt);
                        draw_target(target_col, target_row, COL_TARGET);
                        if (game_mode != MODE_FREE)
                            draw_ball(agent_px, agent_py, COL_AGENT, prev_tilt);
                        draw_ball(px, py, COL_PLAYER, prev_tilt);
                    }
                    
                }
            }

            if (e0) {
                if (b==0x6B) { // left arrow
					
					if (prev_tilt != 'l') {
						prev_tilt = 'l';
						ballSpeed = 0;
					}
				} 
				
                else if (b==0x74) {// right arrow
					  
					if (prev_tilt != 'r') {
						prev_tilt = 'r';
						ballSpeed = 0; 
					}
				}
                else if (b==0x75) {// up arrow
		
					if (prev_tilt != 'u') {
						prev_tilt = 'u';
						ballSpeed = 0;
					}
				}
                else if (b==0x72) {// down arrow
					
					if (prev_tilt != 'd') {
						prev_tilt = 'd';
						ballSpeed = 0;
					}
				}
                e0 = 0;
            } 
            else {
                if (b==0x1D) { // W
					if (prev_tilt != 'u'){
						prev_tilt = 'u';
						ballSpeed = 0;
					}
				} 
                else if (b==0x1B) { // S
					if (prev_tilt != 'd'){
						prev_tilt = 'd';
						ballSpeed = 0;
					}
				}  
                else if (b==0x1C) {//A
					if (prev_tilt != 'l'){
						prev_tilt = 'l';
						ballSpeed=0;
					}
				}
                else if (b==0x23) {//D
					
					if (prev_tilt != 'r') {
						prev_tilt = 'r';
						ballSpeed=0;
					}
				} 
            }
        }


        *(pixel_ctrl + 1) = (int)back_buffer;
        *pixel_ctrl = 1;
        wait_for_vsync();
        back_buffer = (back_buffer == Buffer1) ? Buffer2 : Buffer1;
    }
    return 0;
}
